struct node {
  ll base; // 线性基基底，该二进制位对应对应的基底
  ll id;   // 该基底最初是由哪个下标的数提供的
  ll mask; // 【关键】组成当前 base 需要用到哪些基底位
};

// 标记当前位 i 是由本次插入的新数提供的
mask ^= (1ll << i); 
// 记录：a[i] 这个基底 = (本次的新数 id) ^ (之前消元过程用到的所有基底)
a[i] = { x, id, mask };

class XorBase {
private:
	struct node {
		/*
			base: 线性基基底，该二进制位对应对应的基底
			id: 该二进制位对应的下标
			mask：组成该基底需要取哪些二进制位的基底 (即前置依赖)
		*/
		ll base, id, mask;
	};

	vector<node> a;
	const int MN = 62;
	vector<node> b;

public:
	XorBase() :a(70, node{}) {};

	node& operator[](int x) {
		return a[x];
	}

	// 插入新数
	void insert(ll x, ll id) {
		ll mask = 0;
		for (int i = MN; ~i; i--)
			if (x & (1ll << i)) {
				if (!a[i].base) {
					// 线性基里没有 x，插入 x
					mask ^= (1ll << i);
					a[i] = { x, id, mask };
					return;
				}
				// 线性基里有 x
				x ^= a[i].base;
				mask ^= a[i].mask;
			}
		return;
	}

	// 查是否存在线性基内
	bool check(ll x) {
		for (int i = MN; ~i; i--)
			if (x & (1ll << i))
				if (!a[i].base)return false;
				else x ^= a[i].base;
		return true;
	}

	HashSet<int> query(ll x) {
		// 收集所有要用到的基底
		// 用异或收集，因为出现偶数次的可以被抵消
		ll mask = 0;
		for (int i = MN; ~i; i--)
			if (x & (1ll << i)) {
				x ^= a[i].base;
				mask ^= a[i].mask;
			}

		// 收集基底对应的 id
		var res = HashSet<int>();
		for (int i = MN; ~i; i--)
			if (mask & (1ll << i)) 
				res.insert(a[i].id);
		return res;
	}
};
void solve(int CASE)
{
	ll n; cin >> n;
	var a = vector<ll>(n + 1);
	var b = vector<ll>(n + 1);
	fa(i, 1, n)cin >> a[i];
	fa(i, 1, n)cin >> b[i];

	ll x = 0;
	var xb = XorBase();
	fa(i, 1, n) {
		x ^= a[i];
		xb.insert(b[i] ^ a[i], i);
	}

	if (!x) {
		fa(i, 1, n)cout << a[i] << ' ';
		cout << endl;
		return;
	}

	if (xb.check(x)) {
		var res = xb.query(x);
		fa(i, 1, n) {
			if (res.count(i))cout << b[i] << ' ';
			else cout << a[i] << ' ';
		}cout << endl;
	}
	else cout << -1 << endl;
	return;
}
